#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

static bool controller_check_timeout(const controller_t *controller, uint32_t now_ms)
{
    /* Check if either sensor is stale for more than 1000ms */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        return false; /* Not ready yet, not a timeout */
    }

    uint32_t temp_age = now_ms - controller->last_temperature_ms;
    uint32_t level_age = now_ms - controller->last_level_ms;

    if (temp_age > CONTROLLER_SENSOR_TIMEOUT_MS || level_age > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }

    return false;
}

static void controller_apply_policy(controller_t *controller, uint32_t now_ms)
{
    /* First check timeout */
    if (controller_check_timeout(controller, now_ms)) {
        controller_set_safe_idle(controller);
        return;
    }

    /* Stay in safe state until both sensors are valid */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        return;
    }

    int level = controller->last_level;
    int temp = controller->last_temperature_c;
    int prev_temp = controller->previous_temperature_c;
    bool temp_rising = (temp > prev_temp);

    /* Control policy implementation */

    /* If LEVEL < 60: INLET OPEN, HEATER OFF (FILLING) */
    if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
        return;
    }

    /* LEVEL >= 60: INLET CLOSED */
    controller->inlet_open = false;

    /* If LEVEL < 55: HEATER OFF (regardless of temp) */
